import type { ReactNode } from 'react';import { Navigate,Route,Routes } from 'react-router-dom';import { usePermissions } from '@/hooks/usePermissions';import { ContactsPage } from './pages/ContactsPage';import { ContractsPage } from './pages/ContractsPage';import { QuotationsPage } from './pages/QuotationsPage';import { SupplierDashboardPage } from './pages/SupplierDashboardPage';import { SupplierDetailsPage } from './pages/SupplierDetailsPage';import { SupplierListPage } from './pages/SupplierListPage';
const Gate=({children}:{children:ReactNode})=>{const {can,isLoading}=usePermissions();if(isLoading)return <div className="h-72 animate-pulse rounded-xl bg-slate-200 dark:bg-slate-800"/>;return can('vendors.view')?<>{children}</>:<Navigate to="/dashboard" replace/>;};
export const VendorRoutes=()=> <Routes><Route index element={<Gate><SupplierDashboardPage/></Gate>}/><Route path="suppliers" element={<Gate><SupplierListPage/></Gate>}/><Route path="suppliers/:id" element={<Gate><SupplierDetailsPage/></Gate>}/><Route path="contacts" element={<Gate><ContactsPage/></Gate>}/><Route path="contracts" element={<Gate><ContractsPage/></Gate>}/><Route path="quotations" element={<Gate><QuotationsPage/></Gate>}/><Route path="*" element={<Navigate to="/vendors" replace/>}/></Routes>;
